```class Solution {
public:
    int subtractProductAndSum(int n) {
        int result = 0;
        int product = 1;
        int sum = 0;

        while (n != 0) {
            int digit = n % 10;
            product *= digit;
            sum += digit;
            n /= 10;
        }

        result = product - sum;

        return result;
    }
};```

